function getViewportRect(){return new DOMRect(0,0,getClientWidth(),getClientHeight())}function getClientHeight(){return document.doctype===null?window.innerHeight:document.documentElement.clientHeight}function getClientWidth(){return document.doctype===null?window.innerWidth:document.documentElement.clientWidth}function viewportRectToDocumentRect(viewportRect){const scrollX=document.scrollingElement.scrollLeft;const scrollY=document.scrollingElement.scrollTop;return{top:viewportRect.top+scrollY,left:viewportRect.left+scrollX,bottom:viewportRect.bottom+scrollY,right:viewportRect.right+scrollX,x:viewportRect.x+scrollX,y:viewportRect.y+scrollY,width:viewportRect.width,height:viewportRect.height}}function isIntersecting(rectA,rectB){return getIntersectionPercentage(rectA,rectB)>0}function isContaining(rectA,rectB){return getIntersectionPercentage(rectA,rectB)>=1}function getIntersectionPercentage(rectA,rectB){const effectiveRectB={top:rectB.top,bottom:rectB.bottom,left:rectB.left,right:rectB.right,width:rectB.width,height:rectB.height};if(effectiveRectB.width===0){effectiveRectB.width=1;effectiveRectB.right=effectiveRectB.left+1}if(effectiveRectB.height===0){effectiveRectB.height=1;effectiveRectB.bottom=effectiveRectB.top+1}const x_overlap=Math.max(0,Math.min(rectA.right,effectiveRectB.right)-Math.max(rectA.left,effectiveRectB.left));const y_overlap=Math.max(0,Math.min(rectA.bottom,effectiveRectB.bottom)-Math.max(rectA.top,effectiveRectB.top));const intersectionArea=x_overlap*y_overlap;const areaB=effectiveRectB.width*effectiveRectB.height;return areaB>0?intersectionArea/areaB:0}function getNonZeroBoundingClientRect(target){let rects;if(target&&typeof target.getClientRects==="function"){rects=target.getClientRects()}else if(target instanceof Node){const range=document.createRange();range.selectNodeContents(target);rects=range.getClientRects()}else{return new DOMRect(0,0,0,0)}let minLeft=Infinity;let minTop=Infinity;let maxRight=-Infinity;let maxBottom=-Infinity;let hasValidRect=false;for(let i=0;i<rects.length;i++){const rect=rects[i];if(rect.width>0&&rect.height>0){hasValidRect=true;if(rect.left<minLeft)minLeft=rect.left;if(rect.top<minTop)minTop=rect.top;if(rect.right>maxRight)maxRight=rect.right;if(rect.bottom>maxBottom)maxBottom=rect.bottom}}if(!hasValidRect){return new DOMRect(0,0,0,0)}const width=maxRight-minLeft;const height=maxBottom-minTop;return new DOMRect(minLeft,minTop,width,height)}